// Diff OpenRouter's live catalogue against the ids ickle already knows.
// KNOWN_IDS is the ickle approved-models catalogue baseline (bare openrouter
// vendor/model ids). SYNC THIS when data/approved-models.yaml changes, or
// point this node at a hosted copy of the catalogue instead (see setup doc).
const KNOWN_IDS = new Set([
  // --- keep in sync with ickle-models/data/approved-models.yaml (approved + noted) ---
  "deepseek/deepseek-v3.2",
  "deepseek/deepseek-chat",
  "deepseek/deepseek-chat-v3.1",
  "deepseek/deepseek-r1",
  "deepseek/deepseek-r1-0528",
  "qwen/qwen3-235b-a22b-2507",
  "qwen/qwen3-coder",
  "z-ai/glm-4.6",
  "z-ai/glm-4.7",
  "openai/gpt-5-mini",
  "openai/gpt-4o",
  "google/gemini-2.5-flash",
  "mistralai/mistral-small-3.2-24b-instruct",
  "moonshotai/kimi-k2.5",
  "x-ai/grok-4"
]);

const data = ($input.first().json.data) || [];
// Newcomers: models OpenRouter lists that we have no catalogue line for.
// Cap the cheap-test set so a review run stays cheap and fast.
const MAX_TEST = 8;
const newcomers = data
  .map(m => m.id)
  .filter(id => id && !KNOWN_IDS.has(id))
  .sort();

const toTest = newcomers.slice(0, MAX_TEST);
return toTest.map(id => ({ json: { openrouter_id: id, ickle_id: `openrouter/${id}` } }))
  .concat([{ json: { _summary: true, total_openrouter: data.length, newcomer_count: newcomers.length, tested: toTest.length, newcomers } }]);

// Collect probe results into one review payload.
const items = $input.all();
const lines = items.map(it => {
  const j = it.json;
  const id = (j && j.model) || '(unknown)';
  let reply = '';
  try { reply = j.choices[0].message.content.replace(/\s+/g, ' ').slice(0, 240); }
  catch (e) { reply = '[no reply / error: ' + (j && (j.error && j.error.message || JSON.stringify(j).slice(0,120)) ) + ']'; }
  return `- ${id}: ${reply}`;
}).join('\n');
const msg = `ickle monthly model review\n\n${items.length} newcomer(s) probed via the gateway. Eyeball, then update ickle-models/data/approved-models.yaml (and model-policy fast_cheap if a newcomer beats DeepSeek):\n\n${lines || '(no newcomers this month)'}`;
return [{ json: { ntfy: { topic: 'ickle-model-review', title: 'ickle: monthly model review', message: msg, priority: 3, tags: ['robot','mag'] } } }];
